const regions = ($env.TARGET_REGIONS || 'us-west,uk').split(',').map(r => r.trim()).filter(Boolean);
const geo = {
  'us-west': { gl: 'us', location: 'California, United States', label: 'California' },
  'uk': { gl: 'gb', location: 'United Kingdom', label: 'United Kingdom' }
};
const templates = [
  '{label} data center construction grading permit 2025..2026',
  'hyperscaler data center groundbreaking {label} 2026'
];
const out = [];
for (const region of regions) {
  const g = geo[region] || { gl: 'us', location: '', label: region };
  for (const t of templates) {
    out.push({ json: { q: t.split('{label}').join(g.label), gl: g.gl, location: g.location, region, source: 'serp.dev', num: 4 } });
  }
}
return out;

const src = $('Flatten Results').all();
const items = $input.all();
const targetRegions = String($env.TARGET_REGIONS || 'us-west,uk').split(',').map(r => r.trim()).filter(Boolean);
const num = (v) => { const n = Number(String(v == null ? '' : v).replace(/[^0-9.]/g, '')); return Number.isFinite(n) && n > 0 ? n : null; };
const usWest = new Set(['california','ca','nevada','nv','oregon','or','washington','wa','arizona','az','idaho','id','utah','ut','colorado','co','new mexico','nm','montana','mt','wyoming','wy']);
const ukNames = ['united kingdom','uk','england','scotland','wales','northern ireland','london','hertfordshire','greater london','manchester','birmingham'];
const deriveRegion = (state, location) => {
  const s = String(state || '').toLowerCase().trim();
  const loc = String(location || '').toLowerCase();
  if (usWest.has(s)) return 'us-west';
  if (ukNames.some(u => s.includes(u) || loc.includes(u))) return 'uk';
  return null;
};
const stopwords = new Set(['the','and','of','for','at','a','an','data','center','centre','project','phase','park','plant','site','campus','facility','complex','development','i','ii','iii','iv']);
const isGrounded = (name, title, snippet) => {
  if (!name) return false;
  const text = (String(title||'') + ' ' + String(snippet||'')).toLowerCase();
  const words = name.toLowerCase().split(/[^a-z0-9]+/).filter(w => w.length >= 3 && !stopwords.has(w));
  if (words.length === 0) return false;
  return words.some(w => text.includes(w));
};
const rows = [];
for (let i = 0; i < items.length; i++) {
  const j = items[i].json || {};
  if (j.error) continue;
  const ex = j.output ? j.output : j;
  const s = (src[i] && src[i].json) ? src[i].json : {};
  const link = (s.link || '').trim();
  const name = (ex.name || '').trim();
  if (!link || !name) continue;
  if (!isGrounded(name, s.title, s.snippet)) continue;
  const region = deriveRegion(ex.state, ex.location_raw);
  if (!region || !targetRegions.includes(region)) continue;
  rows.push({ json: {
    source: s.source || 'serp.dev',
    source_url: link,
    dedup_hash: link.toLowerCase(),
    name: name,
    project_type: ex.project_type || 'datacenter',
    description_raw: s.snippet || null,
    location_raw: ex.location_raw || null,
    region: region,
    state: ex.state || null,
    county: ex.county || null,
    owner_company: ex.owner_company || null,
    gc_company: ex.gc_company || null,
    earthworks_sub: ex.earthworks_sub || null,
    est_earthworks_cu_yd: num(ex.est_earthworks_cu_yd),
    site_acres: num(ex.site_acres),
    timeline_stage: ex.timeline_stage || null,
    capex_est: num(ex.capex_est),
    status: 'new'
  } });
}
return rows;

const queries = $('Build Discovery Queries').all();
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const meta = (queries[i] && queries[i].json) ? queries[i].json : {};
  const organic = (items[i].json && Array.isArray(items[i].json.organic)) ? items[i].json.organic : [];
  for (const o of organic) {
    if (!o || !o.link) continue;
    out.push({ json: { title: o.title || '', link: o.link, snippet: o.snippet || '', date: o.date || null, region: meta.region || null, source: meta.source || 'serp.dev', q: meta.q || null } });
  }
}
return out;
